@Controller
@RequestMapping("/saml")
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws Exception {
        String relayState = request.getParameter("RelayState");
        response.sendRedirect(samlService.buildAuthnRequestRedirect(relayState));
    }

    @PostMapping(value = "/acs", produces = MediaType.APPLICATION_JSON_VALUE)
    public void acs(HttpServletRequest request, HttpServletResponse response) throws Exception {
        String samlResponse = request.getParameter("SAMLResponse");
        SamlUser user = samlService.processSamlResponse(samlResponse);
        response.setContentType(MediaType.APPLICATION_JSON_VALUE);
        response.getWriter().write(user.toJson());
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public void metadata(HttpServletResponse response) throws Exception {
        response.setContentType(MediaType.APPLICATION_XML_VALUE);
        response.getWriter().write(samlService.buildSpMetadata());
    }
}

class SamlUser {
    private final String issuer;
    private final String nameId;
    private final Map<String, List<String>> attributes;

    SamlUser(String issuer, String nameId, Map<String, List<String>> attributes) {
        this.issuer = issuer;
        this.nameId = nameId;
        this.attributes = attributes;
    }

    public String toJson() {
        StringBuilder sb = new StringBuilder();
        sb.append("{");
        sb.append("\"issuer\":").append(json(issuer)).append(",");
        sb.append("\"nameId\":").append(json(nameId)).append(",");
        sb.append("\"attributes\":{");
        Iterator<Map.Entry<String, List<String>>> it = attributes.entrySet().iterator();
        while (it.hasNext()) {
            Map.Entry<String, List<String>> e = it.next();
            sb.append(json(e.getKey())).append(":");
            sb.append("[");
            for (int i = 0; i < e.getValue().size(); i++) {
                if (i > 0) sb.append(",");
                sb.append(json(e.getValue().get(i)));
            }
            sb.append("]");
            if (it.hasNext()) sb.append(",");
        }
        sb.append("}}");
        return sb.toString();
    }

    private String json(String value) {
        if (value == null) return "null";
        return "\"" + value.replace("\\", "\\\\").replace("\"", "\\\"") + "\"";
    }
}